mapper.select:
SELECT
	COUNT(*) AS cnt
FROM
	ELIB_HOPE_BOOK
WHERE
	book_code = #{book_code}
AND library_code = #{library_code}
AND com_code = #{com_code}

SELECT
	book_idx
FROM
	ELIB_HOPE_BOOK
WHERE
	book_code = #{book_code}
AND	library_code = #{library_code}
AND com_code = #{com_code}

${pagingTop} SELECT a.book_idx, a.book_code, a.cate_id, a.book_name, a.author_name, a.book_pubname, a.isbn13, a.book_lend, a.lend_total, a.max_lend, a.book_reserve, a.com_code, TO_CHAR(a.book_pubdt, 'YYYY-MM-DD') AS book_pubdt, TO_CHAR(a.add_date, 'YYYY-MM-DD') AS add_date, a.book_regdt, a.use_yn, a.type, a.format, a.book_image, a.parent_id, a.recommend_cnt, a.library_code, a.approved_yn, a.device, ec.cate_name AS cate_name, a.application_status, a.application_add_date, a.application_user_name, a.application_user_id, a.application_user_no, a.application_cancel_date, a.application_cancel_id, a.application_remarks, a.application_approval_date, a.application_approval_id, a.application_cell_phone, CASE WHEN a.library_code = '9999999' THEN '통합' ELSE e.homepage_name END AS library_name, ep.cate_name AS parent_name, cmp.comp_name AS comp_name, CASE a.device WHEN '1' THEN 'PC' WHEN '2' THEN 'PC, 태블릿' WHEN '3' THEN 'PC, 태블릿, 스마트폰' END AS label FROM ELIB_HOPE_BOOK a JOIN CMS_HOMEPAGE e ON a.library_code = SUBSTR(e.homepage_code, 1, 8) LEFT JOIN ELIB_CATEGORY ec ON ec.cate_id = a.cate_id LEFT JOIN ELIB_CATEGORY ep ON ep.cate_id = a.parent_id LEFT JOIN ELIB_COMPANY cmp ON cmp.com_code = a.com_code WHERE a.use_yn != 'N' AND a.application_status IS NOT NULL
AND UPPER(REPLACE(a.${search_type}, ' ')) LIKE '%'||UPPER(REPLACE(#{search_text}, ' '))||'%'
AND UPPER(REPLACE(a.APPLICATION_STATUS, ' ')) LIKE '%'||UPPER(REPLACE(#{application_status}, ' '))||'%' order by a.application_add_date desc ${pagingBottom}

mapper.insert:
SELECT NVL(MAX(book_idx),0)+1 FROM ELIB_HOPE_BOOK
INSERT INTO ELIB_HOPE_BOOK ( book_idx, book_code, book_name, author_name, book_pubname, isbn13, format, book_image, parent_id, device, library_code, max_lend, use_yn, book_lend, book_reserve, com_code, book_pubdt, book_regdt, type, add_id, add_date, approved_yn, cate_id ) VALUES ( #{book_idx}, #{book_code}, #{book_name}, #{author_name}, #{book_pubname}, #{isbn13}, #{format}, #{book_image}, #{parent_id}, #{device}, #{library_code}, #{max_lend}, #{use_yn}, #{book_lend}, #{book_reserve}, #{com_code}, TO_DATE(#{book_pubdt}, 'YYYY-MM-DD'), SYSDATE, #{type}, #{add_id}, SYSDATE, #{approved_yn},
#{parent_id}
#{cate_id}
)

INSERT INTO ELIB_HOPE_BOOKINFO (
	book_idx, book_code, book_info, author_info, book_table, add_id, add_date
) VALUES (
	#{book_idx}, #{book_code}, #{book_info}, #{author_info}, #{book_table}, #{add_id}, SYSDATE
)

mapper.update:
UPDATE ELIB_HOPE_BOOK SET book_code = #{book_code}, book_name = #{book_name}, author_name = #{author_name}, book_pubname = #{book_pubname}, isbn13 = #{isbn13}, format = #{format}, book_image = #{book_image}, book_lend = #{book_lend}, book_reserve = #{book_reserve}, library_code = #{library_code}, com_code = #{com_code}, type = #{type}, use_yn = #{use_yn}, max_lend = #{max_lend}, parent_id = #{parent_id}, device = #{device}, mod_id = #{mod_id}, mod_date = SYSDATE,
cate_id = #{parent_id}
cate_id = #{cate_id}
WHERE book_idx = #{book_idx}

